import{_ as a,c as o,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"Injeção de Contexto: Agent Preditivo | opencode-supermemory","description":"Aprenda o mecanismo de injeção de contexto do opencode-supermemory. Entenda como o Agent obtém perfil do usuário e conhecimento do projeto automaticamente no início da sessão.","frontmatter":{"title":"Injeção de Contexto: Agent Preditivo | opencode-supermemory","sidebarTitle":"Injeção de Contexto","subtitle":"Mecanismo de Injeção Automática de Contexto: Deixando o Agent 'Preditivo'","description":"Aprenda o mecanismo de injeção de contexto do opencode-supermemory. Entenda como o Agent obtém perfil do usuário e conhecimento do projeto automaticamente no início da sessão.","tags":["contexto","injeção","prompt","memória"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"pt/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"pt/supermemoryai/opencode-supermemory/core/context-injection/index.md"}`),t={name:"pt/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function r(i,e,d,l,p,c){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="mecanismo-de-injecao-automatica-de-contexto-deixando-o-agent-preditivo" tabindex="-1">Mecanismo de Injeção Automática de Contexto: Deixando o Agent &quot;Preditivo&quot; <a class="header-anchor" href="#mecanismo-de-injecao-automatica-de-contexto-deixando-o-agent-preditivo" aria-label="Permalink to &quot;Mecanismo de Injeção Automática de Contexto: Deixando o Agent &quot;Preditivo&quot;&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O Que Você Poderá Fazer Após Concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Concluir&quot;">​</a></h2><p>Após concluir esta lição, você será capaz de:</p><ol><li><strong>Compreender</strong> por que o Agent conhece seus hábitos de codificação e a arquitetura do projeto desde o início.</li><li><strong>Dominar</strong> o &quot;modelo tridimensional&quot; de injeção de contexto (perfil do usuário, conhecimento do projeto, memórias relevantes).</li><li><strong>Aprender</strong> a usar palavras-chave (como &quot;Remember this&quot;) para intervir ativamente no comportamento de memória do Agent.</li><li><strong>Configurar</strong> o número de itens injetados, equilibrando o comprimento do contexto com a riqueza de informações.</li></ol><hr><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>Antes do plugin de memória, cada nova sessão era uma folha em branco para o Agent. Você precisava repetidamente dizer: &quot;Uso TypeScript&quot;, &quot;este projeto usa Next.js&quot;.</p><p>A <strong>Injeção de Contexto (Context Injection)</strong> resolve esse problema. É como inserir um &quot;resumo de tarefas&quot; no cérebro do Agent no momento em que ele acorda.</p><h3 id="momento-de-disparo" tabindex="-1">Momento de Disparo <a class="header-anchor" href="#momento-de-disparo" aria-label="Permalink to &quot;Momento de Disparo&quot;">​</a></h3><p>O opencode-supermemory é extremamente contido, acionando a injeção automática apenas na <strong>primeira mensagem da sessão</strong>.</p><ul><li><strong>Por que a primeira?</strong> Porque é o momento crucial para estabelecer o tom da sessão.</li><li><strong>E as mensagens seguintes?</strong> As mensagens subsequentes não injetam automaticamente para evitar interferir no fluxo da conversa, a menos que você acione manualmente (veja abaixo &quot;Disparo por palavras-chave&quot;).</li></ul><h3 id="modelo-de-injecao-tridimensional" tabindex="-1">Modelo de Injeção Tridimensional <a class="header-anchor" href="#modelo-de-injecao-tridimensional" aria-label="Permalink to &quot;Modelo de Injeção Tridimensional&quot;">​</a></h3><p>O plugin obtém paralelamente três tipos de dados, combinando-os em um bloco de prompt <code>[SUPERMEMORY]</code>:</p><table tabindex="0"><thead><tr><th>Dimensão de Dados</th><th>Origem</th><th>Função</th><th>Exemplo</th></tr></thead><tbody><tr><td><strong>1. Perfil do Usuário</strong> (Profile)</td><td><code>getProfile</code></td><td>Suas preferências de longo prazo</td><td>&quot;Usuário prefere programação funcional&quot;, &quot;prefere arrow functions&quot;</td></tr><tr><td><strong>2. Conhecimento do Projeto</strong> (Project)</td><td><code>listMemories</code></td><td>Conhecimento global do projeto atual</td><td>&quot;Este projeto usa Clean Architecture&quot;, &quot;API está em src/api&quot;</td></tr><tr><td><strong>3. Memórias Relevantes</strong> (Relevant)</td><td><code>searchMemories</code></td><td>Experiências passadas relacionadas à sua primeira frase</td><td>Você pergunta &quot;como corrigir este Bug&quot;, ele busca registros de correções anteriores semelhantes</td></tr></tbody></table><hr><h2 id="o-que-e-injetado" tabindex="-1">O Que é Injetado? <a class="header-anchor" href="#o-que-e-injetado" aria-label="Permalink to &quot;O Que é Injetado?&quot;">​</a></h2><p>Quando você envia a primeira mensagem no OpenCode, o plugin默默 insere o seguinte conteúdo no System Prompt em segundo plano.</p><details class="details custom-block"><summary>Clique para ver a estrutura real do conteúdo injetado</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Após ver essas informações, o Agent se comportará como um funcionário experiente que trabalhou neste projeto por muito tempo, em vez de um estagiário recém-chegado.</p><hr><h2 id="mecanismo-de-disparo-por-palavras-chave-nudge" tabindex="-1">Mecanismo de Disparo por Palavras-Chave (Nudge) <a class="header-anchor" href="#mecanismo-de-disparo-por-palavras-chave-nudge" aria-label="Permalink to &quot;Mecanismo de Disparo por Palavras-Chave (Nudge)&quot;">​</a></h2><p>Além da injeção automática no início, você pode &quot;despertar&quot; a função de memória a qualquer momento durante a conversa.</p><p>O plugin possui um <strong>detector de palavras-chave</strong> integrado. Enquanto sua mensagem contiver palavras de gatilho específicas, o plugin enviará uma &quot;dica invisível&quot; (Nudge) ao Agent, forçando-o a chamar a ferramenta de salvamento.</p><h3 id="palavras-de-gatilho-padrao" tabindex="-1">Palavras de Gatilho Padrão <a class="header-anchor" href="#palavras-de-gatilho-padrao" aria-label="Permalink to &quot;Palavras de Gatilho Padrão&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (veja mais na configuração do código fonte)</li></ul><h3 id="exemplo-de-interacao" tabindex="-1">Exemplo de Interação <a class="header-anchor" href="#exemplo-de-interacao" aria-label="Permalink to &quot;Exemplo de Interação&quot;">​</a></h3><p><strong>Sua entrada</strong>:</p><blockquote><p>O formato de resposta da API mudou aqui, <strong>remember</strong> de agora em diante use <code>data.result</code> em vez de <code>data.payload</code>.</p></blockquote><p><strong>Plugin detecta &quot;remember&quot;</strong>:</p><blockquote><p>(injeta dica em segundo plano): <code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Reação do Agent</strong>:</p><blockquote><p>Entendido. Vou me lembrar dessa mudança. <em>(chama <code>supermemory.add</code> em segundo plano para salvar a memória)</em></p></blockquote><hr><h2 id="configuracao-avancada" tabindex="-1">Configuração Avançada <a class="header-anchor" href="#configuracao-avancada" aria-label="Permalink to &quot;Configuração Avançada&quot;">​</a></h2><p>Você pode ajustar o comportamento de injeção modificando <code>~/.config/opencode/supermemory.jsonc</code>.</p><h3 id="itens-de-configuracao-comuns" tabindex="-1">Itens de Configuração Comuns <a class="header-anchor" href="#itens-de-configuracao-comuns" aria-label="Permalink to &quot;Itens de Configuração Comuns&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Se deve injetar o perfil do usuário (padrão true)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Quantas memórias do projeto injetar por vez (padrão 10)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Aumentar permite que o Agent entenda melhor o projeto, mas consome mais Tokens</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Quantos itens de perfil do usuário injetar por vez (padrão 5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Palavras de gatilho personalizadas (suporta regex)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;记一下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;永久保存&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Dica</p><p>Após modificar a configuração, você precisa reiniciar o OpenCode ou recarregar o plugin para que as alterações entrem em vigor.</p></div><hr><h2 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h2><h3 id="p-as-informacoes-injetadas-ocuparao-muitos-tokens" tabindex="-1">P: As informações injetadas ocuparão muitos Tokens? <a class="header-anchor" href="#p-as-informacoes-injetadas-ocuparao-muitos-tokens" aria-label="Permalink to &quot;P: As informações injetadas ocuparão muitos Tokens?&quot;">​</a></h3><p><strong>R</strong>: Ocuparão uma parte, mas geralmente são controláveis. Na configuração padrão (10 memórias do projeto + 5 itens de perfil), isso ocupa cerca de 500-1000 Tokens. Para modelos modernos de larga escala (como Claude 3.5 Sonnet) com contexto de 200k, isso é apenas uma gota no oceano.</p><h3 id="p-por-que-disse-remember-mas-nao-reagiu" tabindex="-1">P: Por que disse &quot;remember&quot; mas não reagiu? <a class="header-anchor" href="#p-por-que-disse-remember-mas-nao-reagiu" aria-label="Permalink to &quot;P: Por que disse &quot;remember&quot; mas não reagiu?&quot;">​</a></h3><p><strong>R</strong>:</p><ol><li>Verifique se a grafia está correta (suporta correspondência por regex).</li><li>Confirme se a API Key está configurada corretamente (se o plugin não foi inicializado, não será acionado).</li><li>O Agent pode decidir ignorar (embora o plugin tenha forçado a dica, o Agent tem a decisão final).</li></ol><h3 id="p-como-as-memorias-relevantes-sao-buscadas" tabindex="-1">P: Como as &quot;memórias relevantes&quot; são buscadas? <a class="header-anchor" href="#p-como-as-memorias-relevantes-sao-buscadas" aria-label="Permalink to &quot;P: Como as &quot;memórias relevantes&quot; são buscadas?&quot;">​</a></h3><p><strong>R</strong>: São baseadas no conteúdo da <strong>sua primeira mensagem</strong> através de busca semântica. Se sua primeira frase for apenas &quot;Hi&quot;, pode não encontrar memórias relevantes úteis, mas &quot;conhecimento do projeto&quot; e &quot;perfil do usuário&quot; ainda serão injetados.</p><hr><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><ul><li><strong>Injeção automática</strong> só é acionada na primeira mensagem da sessão.</li><li><strong>Modelo tridimensional</strong> inclui perfil do usuário, conhecimento do projeto e memórias relevantes.</li><li><strong>Disparo por palavras-chave</strong> permite que você ordene o Agent a salvar memórias a qualquer momento.</li><li>Você pode controlar o volume de informações injetadas através do <strong>arquivo de configuração</strong>.</li></ul><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre <strong><a href="./../tools/">Ferramentas Detalhadas: Ensine o Agent a Memorizar</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como usar manualmente as ferramentas <code>add</code>, <code>search</code>, etc.</li><li>Como visualizar e excluir memórias incorretas.</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Lógica de disparo de injeção</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Formatação do Prompt</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>Configuração padrão</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>Funções principais</strong>:</p><ul><li><code>formatContextForPrompt()</code>: Monta o bloco de texto <code>[SUPERMEMORY]</code>.</li><li><code>detectMemoryKeyword()</code>: Correspondência por regex das palavras de gatilho na mensagem do usuário.</li></ul></details><h2 id="proxima-licao-1" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao-1" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre <strong><a href="./../tools/">Ferramentas Detalhadas: Ensine o Agent a Memorizar</a></strong>.</p><p>Você aprenderá:</p><ul><li>Dominar os 5 modos de ferramentas principais: <code>add</code>, <code>search</code>, <code>profile</code>, <code>list</code>, <code>forget</code></li><li>Como intervir manualmente e corrigir as memórias do Agent</li><li>Acionar o salvamento de memórias usando linguagem natural</li></ul></blockquote>`,57)])])}const h=a(t,[["render",r]]);export{u as __pageData,h as default};
